namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Code { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

namespace UniversityCourseCatalog.Models;

public class Course
{
    public int Id { get; set; }
    public int DepartmentId { get; set; }
    public string Code { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public string InstructorName { get; set; } = string.Empty;
    public string InstructorBio { get; set; } = string.Empty;
    public bool IsFeatured { get; set; }
}

using System.ComponentModel.DataAnnotations;

namespace UniversityCourseCatalog.Models;

public class EnrollmentRequest
{
    [Required(ErrorMessage = "Full name is required.")]
    [StringLength(100)]
    public string StudentName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Student ID is required.")]
    [RegularExpression(@"^[A-Z0-9]{6,10}$", ErrorMessage = "Student ID must be 6–10 uppercase alphanumeric characters.")]
    public string StudentId { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please select a course.")]
    [Range(1, int.MaxValue, ErrorMessage = "Please select a course.")]
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Code = "CS", Name = "Computer Science", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Code = "MATH", Name = "Mathematics", Description = "Pure and applied mathematics including statistics." },
            new() { Id = 3, Code = "ENG", Name = "English", Description = "Literature, writing, and language studies." },
            new() { Id = 4, Code = "PHYS", Name = "Physics", Description = "Study of matter, energy, and the fundamental forces of nature." },
            new() { Id = 5, Code = "HIST", Name = "History", Description = "Exploration of past events and civilizations." }
        };

        _courses = new List<Course>
        {
            new() { Id = 1, DepartmentId = 1, Code = "CS101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using Python. Topics include variables, control flow, functions, and basic data structures.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience in software engineering and computer science education. She holds a PhD from MIT.", IsFeatured = true },
            new() { Id = 2, DepartmentId = 1, Code = "CS201", Title = "Data Structures & Algorithms", Description = "In-depth study of data structures (trees, graphs, hash tables) and algorithm design techniques including divide-and-conquer and dynamic programming.", Credits = 4, Schedule = "Tue/Thu 10:30–11:50 AM", InstructorName = "Dr. James Rodriguez", InstructorBio = "Dr. Rodriguez specializes in algorithm optimization and has published over 40 papers in top-tier conferences.", IsFeatured = true },
            new() { Id = 3, DepartmentId = 1, Code = "CS310", Title = "Database Systems", Description = "Relational database design, SQL, transaction processing, and an introduction to NoSQL systems.", Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM", InstructorName = "Prof. Linda Park", InstructorBio = "Prof. Park worked at Oracle for a decade before joining academia. Her research focuses on distributed databases.", IsFeatured = false },
            new() { Id = 4, DepartmentId = 2, Code = "MATH101", Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions with applications.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", InstructorName = "Dr. Alan Turing Jr.", InstructorBio = "Dr. Turing Jr. is an award-winning educator known for making abstract concepts accessible.", IsFeatured = true },
            new() { Id = 5, DepartmentId = 2, Code = "MATH201", Title = "Linear Algebra", Description = "Vector spaces, linear transformations, matrices, determinants, and eigenvalues.", Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", InstructorName = "Dr. Maria Gonzalez", InstructorBio = "Dr. Gonzalez's research spans numerical linear algebra and machine learning foundations.", IsFeatured = false },
            new() { Id = 6, DepartmentId = 3, Code = "ENG110", Title = "Academic Writing", Description = "Develop skills in analytical reading, critical thinking, and persuasive writing for academic contexts.", Credits = 3, Schedule = "Tue/Thu 9:00–10:20 AM", InstructorName = "Prof. David Kim", InstructorBio = "Prof. Kim is a published author and has taught composition for 20 years.", IsFeatured = false },
            new() { Id = 7, DepartmentId = 3, Code = "ENG250", Title = "American Literature", Description = "Survey of major American literary works from the colonial period to the present.", Credits = 3, Schedule = "Mon/Wed 11:00 AM–12:20 PM", InstructorName = "Dr. Rachel Adams", InstructorBio = "Dr. Adams is a Pulitzer-nominated critic specializing in 20th-century American fiction.", IsFeatured = true },
            new() { Id = 8, DepartmentId = 4, Code = "PHYS101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Calculus-based introductory physics.", Credits = 4, Schedule = "Mon/Wed/Fri 1:00–1:50 PM + Lab Thu 2:00–4:00 PM", InstructorName = "Dr. Neil Patel", InstructorBio = "Dr. Patel's engaging lecture style has earned him the university's Distinguished Teaching Award three times.", IsFeatured = false },
            new() { Id = 9, DepartmentId = 4, Code = "PHYS220", Title = "Electromagnetism", Description = "Electric and magnetic fields, Maxwell's equations, and electromagnetic waves.", Credits = 4, Schedule = "Tue/Thu 10:00–11:20 AM + Lab Fri 1:00–3:00 PM", InstructorName = "Dr. Emily Watson", InstructorBio = "Dr. Watson conducts research in photonics and has multiple patents in optical sensing.", IsFeatured = false },
            new() { Id = 10, DepartmentId = 5, Code = "HIST101", Title = "World History to 1500", Description = "Survey of global civilizations from prehistory through the late medieval period.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", InstructorName = "Dr. Marcus Johnson", InstructorBio = "Dr. Johnson is the author of three books on ancient Mediterranean trade networks.", IsFeatured = false },
            new() { Id = 11, DepartmentId = 5, Code = "HIST205", Title = "Modern European History", Description = "Europe from the Enlightenment to the present, covering revolutions, wars, and cultural shifts.", Credits = 3, Schedule = "Tue/Thu 3:00–4:20 PM", InstructorName = "Dr. Sofia Müller", InstructorBio = "Dr. Müller is a visiting scholar from the University of Berlin specializing in Cold War history.", IsFeatured = true }
        };
    }

    public List<Department> GetAllDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetAllCourses() => _courses;

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> SearchCourses(string? searchTerm, int? departmentId)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public List<Course> GetCoursesByDepartment(int departmentId) =>
        _courses.Where(c => c.DepartmentId == departmentId).ToList();
}

