@page "/"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog

<PageTitle>University Course Catalog</PageTitle>

<div class="container">
    <div class="hero">
        <h1>University Course Catalog</h1>
        <p class="lead">Explore our departments and courses. Find your next learning adventure.</p>
        <a href="/courses" class="btn btn-primary btn-lg">Browse All Courses</a>
    </div>

    <section class="mt-5">
        <h2>Featured Courses</h2>
        <div class="row mt-3">
            @foreach (var course in featuredCourses)
            {
                <div class="col-md-4 mb-4">
                    <div class="card h-100">
                        <div class="card-body">
                            <h5 class="card-title">@course.Code — @course.Title</h5>
                            <p class="card-text text-muted">@course.Credits credits · @GetDepartmentName(course.DepartmentId)</p>
                            <p class="card-text">@Truncate(course.Description, 100)</p>
                        </div>
                        <div class="card-footer bg-transparent">
                            <a href="/courses/@course.Id" class="btn btn-outline-primary btn-sm">View Details</a>
                        </div>
                    </div>
                </div>
            }
        </div>
    </section>

    <section class="mt-5">
        <h2>Departments</h2>
        <div class="row mt-3">
            @foreach (var dept in departments)
            {
                <div class="col-md-4 mb-3">
                    <div class="card">
                        <div class="card-body">
                            <h5 class="card-title">@dept.Name</h5>
                            <p class="card-text">@dept.Description</p>
                            <a href="/courses?departmentId=@dept.Id" class="btn btn-outline-secondary btn-sm">View Courses</a>
                        </div>
                    </div>
                </div>
            }
        </div>
    </section>
</div>

@code {
    private List<Course> featuredCourses = new();
    private List<Department> departments = new();

    protected override void OnInitialized()
    {
        featuredCourses = Catalog.GetFeaturedCourses();
        departments = Catalog.GetAllDepartments();
    }

    private string GetDepartmentName(int departmentId)
    {
        return Catalog.GetDepartment(departmentId)?.Name ?? "Unknown";
    }

    private static string Truncate(string text, int maxLength)
    {
        if (string.IsNullOrEmpty(text) || text.Length <= maxLength) return text;
        return text[..maxLength] + "…";
    }
}

@page "/courses"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog
@inject NavigationManager Navigation
@rendermode InteractiveServer

<PageTitle>Course Catalog</PageTitle>

<div class="container">
    <h1 class="mb-4">Course Catalog</h1>

    <div class="row mb-4">
        <div class="col-md-6">
            <input type="text" class="form-control" placeholder="Search courses…"
                   @bind="searchTerm" @bind:event="oninput" />
        </div>
        <div class="col-md-4">
            <select class="form-select" @bind="selectedDepartmentId">
                <option value="0">All Departments</option>
                @foreach (var dept in departments)
                {
                    <option value="@dept.Id">@dept.Name</option>
                }
            </select>
        </div>
    </div>

    @if (filteredCourses.Count == 0)
    {
        <div class="alert alert-info">No courses found matching your criteria.</div>
    }
    else
    {
        <div class="row">
            @foreach (var course in filteredCourses)
            {
                <div class="col-md-6 mb-3">
                    <div class="card">
                        <div class="card-body">
                            <h5 class="card-title">@course.Code — @course.Title</h5>
                            <p class="card-text text-muted">
                                @course.Credits credits · @GetDepartmentName(course.DepartmentId) · @course.Schedule
                            </p>
                            <a href="/courses/@course.Id" class="btn btn-outline-primary btn-sm">View Details</a>
                        </div>
                    </div>
                </div>
            }
        </div>
    }
</div>

@code {
    private List<Department> departments = new();
    private List<Course> filteredCourses = new();

    private string _searchTerm = string.Empty;
    private int _selectedDepartmentId;

    [SupplyParameterFromQuery(Name = "departmentId")]
    public int? QueryDepartmentId { get; set; }

    private string searchTerm
    {
        get => _searchTerm;
        set { _searchTerm = value; FilterCourses(); }
    }

    private int selectedDepartmentId
    {
        get => _selectedDepartmentId;
        set { _selectedDepartmentId = value; FilterCourses(); }
    }

    protected override void OnInitialized()
    {
        departments = Catalog.GetAllDepartments();
        if (QueryDepartmentId.HasValue)
            _selectedDepartmentId = QueryDepartmentId.Value;
        FilterCourses();
    }

    private void FilterCourses()
    {
        filteredCourses = Catalog.SearchCourses(
            string.IsNullOrWhiteSpace(_searchTerm) ? null : _searchTerm,
            _selectedDepartmentId > 0 ? _selectedDepartmentId : null);
    }

    private string GetDepartmentName(int departmentId)
    {
        return Catalog.GetDepartment(departmentId)?.Name ?? "Unknown";
    }
}

