@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog
@rendermode InteractiveServer

<PageTitle>Enrollment Request</PageTitle>

<div class="container">
    <h1 class="mb-4">Enrollment Request</h1>

    @if (submitted)
    {
        <div class="alert alert-success">
            <h4>Request Submitted!</h4>
            <p>Thank you, <strong>@model.StudentName</strong>. Your enrollment request for
                <strong>@GetCourseName(model.CourseId)</strong> has been received.
                You will be notified via your student portal.</p>
        </div>
        <a href="/courses" class="btn btn-primary">Browse More Courses</a>
    }
    else
    {
        <EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="enrollment">
            <DataAnnotationsValidator />
            <ValidationSummary class="text-danger mb-3" />

            <div class="mb-3">
                <label for="studentName" class="form-label">Full Name</label>
                <InputText id="studentName" class="form-control" @bind-Value="model.StudentName" />
                <ValidationMessage For="() => model.StudentName" class="text-danger" />
            </div>

            <div class="mb-3">
                <label for="studentId" class="form-label">Student ID</label>
                <InputText id="studentId" class="form-control" @bind-Value="model.StudentId" placeholder="e.g. STU12345" />
                <ValidationMessage For="() => model.StudentId" class="text-danger" />
            </div>

            <div class="mb-3">
                <label for="courseId" class="form-label">Course</label>
                <InputSelect id="courseId" class="form-select" @bind-Value="model.CourseId">
                    <option value="0">— Select a course —</option>
                    @foreach (var course in courses)
                    {
                        <option value="@course.Id">@course.Code — @course.Title</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => model.CourseId" class="text-danger" />
            </div>

            <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
        </EditForm>
    }
</div>

